function ParkOperations({ sectionId }: { sectionId: string }) {
  const config = PARK_CONFIGS[sectionId] ?? PARK_CONFIGS["operations-center"];
  const trend = useMemo(() => getParkTrend(sectionId), [sectionId]);
  return <>
    <MetricGrid metrics={config.metrics} />
    <div className="grid gap-4 xl:grid-cols-[1.35fr_.85fr]"><AirportPanel title={config.title} subtitle={config.subtitle}><div className="p-3"><AirportTrendChart data={trend} height={270} color="#60a5fa" /></div></AirportPanel><AirportPanel title="Live operational entities" subtitle="Select an entity to open its spatial context"><EntityList entities={config.entities} /></AirportPanel></div>
    <div className="grid gap-4 xl:grid-cols-[1fr_1fr]"><AirportPanel title="Operational events and response feed"><div className="p-3"><AirportTimeline events={config.events} /></div></AirportPanel><AirportPanel title="Capacity and utilization by domain"><div className="grid grid-cols-2 gap-3 p-4">{config.capacities.map(([label,value]) => <CapacityBar key={label} label={label} value={value} />)}</div></AirportPanel></div>
  </>;
}

