function UnifiedDataLake(){const layers=[["Ingestion","OT, IoT, GIS, BIM, enterprise, documents","MQTT · OPC UA · BACnet · Modbus · API"],["Bronze","Raw immutable telemetry and files","Time-series · events · video metadata"],["Silver","Cleansed, standardized and spatially aligned","Assets · plots · tenants · networks"],["Gold","Decision-ready domain data products","Operations · ESG · investment · FM"],["AI / Digital Twin","Simulation, prediction and governed actions","Models · scenarios · copilots · workflow"]] as const;return <><MetricGrid metrics={[["Data domains","7","OT / IT / Spatial / ESG","cyan"],["Streaming feeds","112","Live","blue"],["Median freshness","6 sec","Healthy","emerald"],["Canonical models","42","Park semantics","cyan"],["Data products","84","Decision-ready","violet"],["Lineage coverage","92.4%","Improving","amber"]]}/><div className="grid gap-4 xl:grid-cols-[1.2fr_.8fr]"><AirportPanel title="Unified data lakehouse architecture"><div className="space-y-3 p-4">{layers.map(([name,detail,tech],index)=><div key={name} className="rounded-xl border border-cyan-400/15 bg-cyan-400/[.045] p-4"><div className="flex justify-between gap-4"><div><p className="text-[9px] uppercase tracking-[.16em] text-cyan-300">Layer 0{index+1}</p><h3 className="mt-1 text-sm font-semibold text-white">{name}</h3><p className="mt-1 text-[10px] text-slate-300">{detail}</p></div><p className="max-w-[230px] text-right text-[9px] text-slate-500">{tech}</p></div></div>)}</div></AirportPanel><AirportPanel title="Decision domains unlocked"><div className="space-y-2 p-3">{["Single source of truth for land, tenants, assets and infrastructure","Power-quality protection for semiconductor and precision manufacturing","Environmental compliance, hazardous-waste and ESG reporting","Flood, pollution and utility-outage simulation","Investor and tenant digital-service workflows","Governed AI recommendations with audit and approval"].map((x,i)=><div key={x} className="rounded-lg border border-white/[.06] bg-white/[.025] p-3"><div className="flex gap-3"><Database size={14} className="text-cyan-300"/><p className="text-[10px] text-slate-300">{x}</p></div><div className="mt-2"><AirportStatusBadge status={i<4?"normal":"info"}/></div></div>)}</div></AirportPanel></div></>}

function EdgeArchitecture(){const layers=[["Layer 1 · Edge devices","Smart meters, sensors, analyzers, cameras, PLC/DDC, UAV trackers","TLS, hardware identity, VLAN/zone isolation"],["Layer 2 · Network & data","Fiber, private 5G, gateways, time-series DB, data lake","NGFW, IPS, segmentation, service accounts"],["Layer 3 · Applications","IOC, Digital Twin 2D/3D, EBO, CMMS, CRM, AI and What-if","MFA, RBAC/ABAC, data permissions, audit trail"]] as const;return <><MetricGrid metrics={[["Edge devices","18,420","98.9% online","cyan"],["Gateways","284 / 286","Healthy","blue"],["Network segments","84","Enforced","emerald"],["Data services","42","Active","cyan"],["MFA coverage","98.6%","Improving","emerald"],["Audit events","2.84M/d","Immutable","violet"]]}/><AirportPanel title="Three-layer data and security architecture"><div className="grid grid-cols-3 gap-4 p-4">{layers.map(([name,components,security],index)=><div key={name} className="relative rounded-2xl border border-cyan-400/15 bg-gradient-to-br from-cyan-400/[.07] to-transparent p-5"><span className="grid h-10 w-10 place-items-center rounded-xl bg-cyan-400/10 text-cyan-300">{index===0?<Cpu size={19}/>:index===1?<Network size={19}/>:<Sparkles size={19}/>}</span><h3 className="mt-4 text-sm font-semibold text-white">{name}</h3><p className="mt-3 text-[10px] leading-relaxed text-slate-300">{components}</p><div className="mt-5 rounded-lg border border-emerald-400/15 bg-emerald-400/[.045] p-3"><p className="text-[8px] uppercase tracking-[.14em] text-emerald-300">Security controls</p><p className="mt-2 text-[9px] leading-relaxed text-slate-400">{security}</p></div>{index<2&&<Route size={20} className="absolute -right-[18px] top-1/2 text-cyan-300/50"/>}</div>)}</div></AirportPanel><div className="grid gap-4 xl:grid-cols-3">{[["Protocols","Modbus · OPC UA · BACnet · MQTT"],["Data platforms","PostgreSQL · Time-series · S3/Data Lake"],["Application stack","React · Three.js · GIS · Python AI"]].map(([a,b])=><AirportPanel key={a} title={a}><div className="p-4 text-[10px] text-slate-300">{b}</div></AirportPanel>)}</div></>}

function MiniDataCenter(){return <><MetricGrid metrics={[["Rack utilization","68%","Healthy","cyan"],["Power load","182 kW","+4%","blue"],["Cooling load","76%","Stable","cyan"],["PUE","1.42","Efficient","emerald"],["Replication lag","18 sec","Target <30","emerald"],["Critical alarms","0","Nominal","emerald"]]}/><div className="grid gap-4 xl:grid-cols-[1.05fr_.95fr]"><AirportPanel title="Mini data center operational profile"><div className="grid grid-cols-2 gap-2 p-4">{[["Compute racks","12 / 12 online"],["Storage pools","4 / 4 healthy"],["Network fabric","2 core + 8 leaf"],["UPS","2N · 92 min"],["Cooling","N+1 CRAH"],["Edge nodes","18 remote · synced"]].map(([a,b])=><div key={a} className="rounded-lg border border-white/[.07] bg-white/[.03] p-3"><p className="text-[10px] text-slate-500">{a}</p><p className="mt-1 text-sm font-semibold text-white">{b}</p></div>)}</div></AirportPanel><AirportPanel title="Role in high-tech park resilience"><div className="space-y-2 p-3">{["Local continuity for OT, EBO, video and critical utilities","Edge analytics for power quality, security and environmental events","Sovereign storage for operational data, BIM/GIS and evidence","Low-latency private 5G and IoT integration","Fast recovery and governed synchronization with enterprise cloud"].map(x=><div key={x} className="rounded-lg border border-cyan-400/14 bg-cyan-400/[.05] p-3 text-[10px] text-slate-300">{x}</div>)}</div></AirportPanel></div></>}

function IntegrationHub(){const rows=SYSTEM_CONNECTIONS.map((r,index)=>({id:`INT-${index+1}`,system:r[0],domain:r[1],protocol:r[2],availability:r[3],lastMessage:r[4],latency:r[5],quality:r[6],owner:["Park Operations","Data Platform","Facility OT","Security Operations"][index%4]}));type R=(typeof rows)[number];const cols:AirportColumn<R>[]=[{key:"system",label:"System",render:r=><span className="font-semibold text-cyan-300">{r.system}</span>},{key:"domain",label:"Domain"},{key:"protocol",label:"Connection / Protocol"},{key:"availability",label:"Availability"},{key:"lastMessage",label:"Last message"},{key:"latency",label:"Latency"},{key:"quality",label:"Data quality"},{key:"owner",label:"Owner"}];return <><MetricGrid metrics={[["Connected systems","112 / 115","97.4%","cyan"],["Messages / sec","68,420","Peak 94k","blue"],["API availability","99.97%","Healthy","emerald"],["Median latency","31 ms","Target <80","cyan"],["Data quality","97.8%","+0.8 pt","emerald"],["Integration errors","18","1 critical","amber"]]}/><div className="grid gap-4 xl:grid-cols-4">{[["OT",28,"SCADA · EBO · EMS · Water"],["Spatial",18,"GIS · BIM · 3D Tiles"],["Enterprise",24,"CRM · ERP · DMS · Portal"],["IoT & Security",42,"Sensors · CCTV · ACS · ANPR"]].map(([a,b,c])=><AirportPanel key={String(a)} title={String(a)}><div className="p-4"><p className="text-2xl font-semibold text-white">{b}</p><p className="mt-1 text-[10px] text-slate-500">{c}</p></div></AirportPanel>)}</div><AirportDataTable rows={rows} columns={cols} total={rows.length} page={1} pageSize={25} onPageChange={()=>undefined} onPageSizeChange={()=>undefined} onRowClick={r=>toast.info(`${r.system} integration detail opened`)}/></>}

function DataQuality(){return <><MetricGrid metrics={[["Completeness","97.8%","1,842 missing","cyan"],["Freshness","98.6%","18 stale feeds","emerald"],["Accuracy","96.9%","42 flags","blue"],["Lineage","92.4%","84 paths","amber"],["BIM/GIS mapping","94.7%","1,318 gaps","cyan"],["Access governance","98.2%","12 reviews","emerald"]]}/><AirportPanel title="Enterprise data-quality dimensions"><div className="grid grid-cols-4 gap-3 p-4">{[["Land & planning",98.4,"12 missing plot fields"],["Tenant & contracts",97.8,"18 stale records"],["Infrastructure OT",98.9,"42 sensor flags"],["Environment",99.2,"6 calibration gaps"],["BIM/GIS",94.7,"1,318 unmapped assets"],["Maintenance",96.8,"84 missing failure codes"],["Security evidence",98.6,"18 metadata gaps"],["Data lineage",92.4,"84 undocumented paths"]].map(([label,value,detail])=><div key={String(label)} className="rounded-xl border border-white/[.07] bg-white/[.025] p-4"><div className="flex justify-between"><span className="text-[10px] text-slate-400">{label}</span><b className="text-sm text-white">{value}%</b></div><div className="mt-3 h-1.5 overflow-hidden rounded bg-white/[.06]"><div className="h-full rounded bg-cyan-300" style={{width:`${value}%`}}/></div><p className="mt-2 text-[9px] text-slate-600">{detail}</p></div>)}</div></AirportPanel></>}

function MetricGrid({metrics}:{metrics:Metric[]}){return <div className={`grid grid-cols-3 gap-2 ${metrics.length>6?"xl:grid-cols-5":"xl:grid-cols-6"}`}>{metrics.map(([label,value,trend,tone])=><AirportMetricCard key={label} label={label} value={value} trend={trend} compact tone={tone??"cyan"}/>)}</div>}
function EntityList({entities}:{entities:string[]}){return <div className="space-y-2 p-3">{entities.map((entity,index)=><button key={entity} onClick={()=>toast.info(entity)} className="flex w-full items-center justify-between rounded-lg border border-white/[.06] bg-white/[.025] p-3 text-left"><span className="text-[10px] text-slate-300">{entity}</span><AirportStatusBadge status={index===2||String(entity).includes("alert")||String(entity).includes("Incident")?"warning":"normal"}/></button>)}</div>}
function CapacityBar({label,value}:{label:string;value:number}){return <div><div className="mb-1 flex justify-between text-[10px]"><span className="text-slate-400">{label}</span><b className="text-white">{value}%</b></div><div className="h-2 overflow-hidden rounded-full bg-white/[.06]"><motion.div initial={{width:0}} animate={{width:`${value}%`}} className={`h-full rounded-full ${value>85?"bg-amber-400":"bg-cyan-400"}`}/></div></div>}
